record.field:
input_sick_days = inputs.get('SICK_DAYS')
if input_sick_days and input_sick_days.amount > 0:
    sick_days = input_sick_days.amount
    if sick_days <= 21:
        result = (contract.wage / 30) * sick_days * 1
    elif sick_days <= 35:
        result = (contract.wage / 30) * sick_days * 0.75
    elif sick_days <= 70:
        result = (contract.wage / 30) * sick_days * 0.50
    elif sick_days <= 182:
        result = (contract.wage / 30) * sick_days * 0.35
    else:
        result = 0
else:
    result = 0  # Ensures rule does NOT run if SICK_DAYS is missing
